import UIKit
import Foundation

struct PromoCode {
    let code: String
    let discountPercentage: Double
}

class ViewController: UIViewController {

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIApplication.RestorationIdentifier: Any]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb {
            if let incomingURL = userActivity.webpageURL {
                if let promoCodeComponents = URLComponents(url: incomingURL, resolvingAgainstCurrent: &incomingURL) {
                    if let queryItems = promoCodeComponents.queryItems,
                       let codeItem = queryItems.first(where: {$0.name == "code"}),
                       let discountItem = queryItems.first(where: {$0.name == "discount"}) {

                        if let promoCode = createPromoCode(with: codeItem.value, discount: Double(discountItem.value)!) {
                            applyPromoCodeToUserAccount(promoCode: promoCode)
                        }
                    }
                }
            }
        }
        return true
    }

    private func createPromoCode(with code: String, discount: Double) -> PromoCode? {
        // You can implement your own logic for creating and validating the promo code here.
        return PromoCode(code: code, discountPercentage: discount)
    }

    private func applyPromoCodeToUserAccount(promoCode: PromoCode) {
        // Implement your logic for applying the promo code to a user account.
        print("Applying promo code \(promoCode.code) with discount percentage \(promoCode.discountPercentage)")
    }
